              </button>
            </div>

            {isInflected && (
              <div className="mb-6 flex items-center gap-3 flex-wrap">
                <span className="text-[10px] uppercase tracking-[0.3em] text-stone-400 font-bold">Lemma Reference:</span>
                <span className="text-xl sm:text-2xl serif italic text-[#7c1a1a] lowercase underline decoration-stone-200 underline-offset-8 break-all">{entry.lemma}</span>
              </div>
            )}

            <div className="flex flex-wrap gap-2 sm:gap-3">
              <span className="bg-stone-900 text-white text-[9px] px-3 sm:px-4 py-1.5 font-black uppercase tracking-[0.3em] rounded-sm">
                {entry.philology.partOfSpeech}
              </span>
              {entry.cefrLevel && entry.sourceLang !== 'Uzbek' && (
                <span className="bg-[#7c1a1a] text-white text-[9px] px-3 sm:px-4 py-1.5 font-black uppercase tracking-[0.3em] rounded-sm">
                  {entry.cefrLevel}
                </span>
              )}
              {entry.philology.gender && (
                <span className="border border-stone-200 text-stone-600 text-[9px] px-3 sm:px-4 py-1.5 font-black uppercase tracking-[0.3em] rounded-sm">
                  {entry.philology.gender}
                </span>
              )}
              <span className="bg-stone-50 text-stone-400 text-[9px] px-3 sm:px-4 py-1.5 font-black uppercase tracking-[0.3em] rounded-sm border border-stone-100">
                {entry.sourceLang.substring(0, 3)}
              </span>
            </div>
          </div>

          <div className="md:text-right border-t md:border-t-0 pt-8 md:pt-0 w-full md:w-auto min-w-0">
