                    {lit.translation && <p className="text-lg md:text-xl serif italic text-stone-400 mb-6 leading-relaxed break-words">{lit.translation}</p>}
                    <div className="text-[10px] uppercase tracking-[0.3em] font-black text-stone-500 flex items-center gap-3 flex-wrap">
