import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const audioBufferCache = new Map<string, AudioBuffer>();
let sharedAudioCtx: AudioContext | null = null;
let isResuming = false;

/**
 * Standardizes the AudioContext retrieval.
 */
export function getAudioContext() {
  if (!sharedAudioCtx) {
    const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
    if (AudioContextClass) {
      sharedAudioCtx = new AudioContextClass({ sampleRate: 24000 });
    }
  }
  return sharedAudioCtx;
}

/**
 * Robustly resumes the AudioContext within a user gesture.
 */
export async function resumeAudioContext(): Promise<void> {
  const ctx = getAudioContext();
  if (!ctx || isResuming) return;

  if (ctx.state === 'running') return;

  isResuming = true;
  try {
    await ctx.resume();

    // Critical iOS/macOS Fix: Inject a tiny silent buffer to "warm" the audio hardware.
    const buffer = ctx.createBuffer(1, 1, 24000);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  } catch (e) {
    // Silent catch for environment restrictions
  } finally {
    isResuming = false;
  }
}

/**
 * Custom base64 decoder with strict sanitization for iOS Safari atob().
 */
function decode(base64: string): Uint8Array {
  const normalized = base64.replace(/[^A-Za-z0-9+/=]/g, "");

  try {
    const binaryString = atob(normalized);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  } catch (e) {
    console.error("Base64 decoding failed on iOS", e);
    return new Uint8Array(0);
  }
}

/**
 * Decodes raw PCM 16-bit audio bytes into an AudioBuffer.
 */
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  if (data.length === 0) throw new Error("Audio data is empty");

  const arrayBuffer = data.buffer.slice(data.byteOffset, data.byteOffset + data.byteLength);
  const dataInt16 = new Int16Array(arrayBuffer);

  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

/**
 * Synthesizes and plays text via Gemini TTS.
 * Returns the base64 audio string if it was generated or provided.
 */
export async function speak(text: string, lang: Language, existingData?: string): Promise<string | undefined> {
  if (!text || !text.trim()) return;

  const ctx = getAudioContext();
  if (!ctx) return;

  const cacheKey = `${text.trim()}:${lang}`;

  const playBuffer = (buffer: AudioBuffer) => {
    if (ctx.state !== 'running') {
      ctx.resume().catch(() => {});
    }
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  };

  // If we have data provided, use it immediately
  if (existingData) {
    try {
      let buffer = audioBufferCache.get(cacheKey);
      if (!buffer) {
        buffer = await decodeAudioData(decode(existingData), ctx, 24000, 1);
        audioBufferCache.set(cacheKey, buffer);
      }
      playBuffer(buffer);
      return existingData;
    } catch (e) {
      console.warn("Failed to play provided persistent audio, falling back to API.");
    }
  }

  // Check in-memory cache
  if (audioBufferCache.has(cacheKey)) {
    playBuffer(audioBufferCache.get(cacheKey)!);
    return; // Don't return data if we already had it in memory to avoid redundant saves
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const voiceName = VOICE_MAPPING[lang] || 'Puck';

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say clearly: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
    audioBufferCache.set(cacheKey, audioBuffer);
    playBuffer(audioBuffer);

    return base64Audio;
  } catch (error) {
    console.error("Philologist Voice Engine Failure:", error);
    return undefined;
  }
}

import React from 'react';
import { LexicalEntry } from '../types';
import { speak, resumeAudioContext } from '../services/tts';
import { triggerHaptic } from '../services/telegram';

interface Props {
  entry: LexicalEntry;
  onSearchTerm?: (term: string) => void;
  onUpdateEntry?: (entry: LexicalEntry) => void;
}

const Shimmer: React.FC<{ className?: string }> = ({ className }) => (
  <div className={`animate-pulse bg-stone-100 rounded-sm ${className}`} />
);

const ResultCard: React.FC<Props> = ({ entry, onSearchTerm, onUpdateEntry }) => {
  const isInflected = entry.lemma && entry.lemma.toLowerCase() !== entry.term.toLowerCase();

  const handleSpeak = async (text: string, lang: any, isSource: boolean) => {
    triggerHaptic('light');
    await resumeAudioContext();

    const existingAudio = isSource ? entry.sourceAudio : entry.targetAudio;
    const generatedAudio = await speak(text, lang, existingAudio);

    // If audio was generated for the first time, save it to the entry
    if (generatedAudio && !existingAudio && onUpdateEntry) {
      const updatedEntry = { ...entry };
      if (isSource) updatedEntry.sourceAudio = generatedAudio;
      else updatedEntry.targetAudio = generatedAudio;
      onUpdateEntry(updatedEntry);
    }
  };

  const displayIdioms = entry.idioms && entry.idioms.length > 0 
    ? entry.idioms 
    : (entry.realLifeSentences || []);

  return (
    <div className="bg-white border border-stone-200 shadow-sm rounded-sm animate-in fade-in slide-in-from-bottom-4 duration-700 overflow-hidden w-full">
      {/* Primary Header Section */}
      <div className="p-6 sm:p-8 md:p-12 lg:p-16 border-b border-stone-100 bg-[#fcfcfb]">
        <div className="flex flex-col md:flex-row justify-between items-start gap-8 md:gap-12">
          {/* Source Side */}
          <div className="flex-1 min-w-0 w-full">
            <div className="flex items-start justify-between gap-4 mb-4">
              <h1 className="text-4xl sm:text-5xl md:text-6xl lg:text-8xl serif font-black tracking-tighter lowercase leading-none text-stone-900 overflow-wrap-anywhere break-words flex-1 min-w-0">
                {entry.term}
              </h1>
              <button 
                onClick={() => handleSpeak(entry.term, entry.sourceLang, true)} 
                title="Pronounce"
                className="text-stone-300 hover:text-[#7c1a1a] transition-all p-2.5 sm:p-3 hover:bg-white rounded-full border border-transparent hover:border-stone-100 shadow-sm flex-shrink-0 mt-1 sm:mt-2"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="sm:w-6 sm:h-6"><path d="M11 5L6 9H2v6h4l5 4V5z"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/></svg>
              </button>
            </div>

            {isInflected && (
              <div className="mb-6 flex items-baseline gap-2 flex-wrap min-w-0">
                <span className="text-[9px] uppercase tracking-[0.2em] text-stone-400 font-bold flex-shrink-0">Lemma:</span>
                <span className="text-lg sm:text-xl serif italic text-[#7c1a1a] lowercase underline decoration-stone-200 underline-offset-4 overflow-wrap-anywhere break-words">{entry.lemma}</span>
              </div>
            )}

            <div className="flex flex-wrap gap-2">
              <span className="bg-stone-900 text-white text-[8px] px-2.5 py-1.5 font-black uppercase tracking-[0.2em] rounded-sm">
                {entry.philology.partOfSpeech}
              </span>
              {entry.cefrLevel && entry.sourceLang !== 'Uzbek' && (
                <span className="bg-[#7c1a1a] text-white text-[8px] px-2.5 py-1.5 font-black uppercase tracking-[0.2em] rounded-sm">
                  {entry.cefrLevel}
                </span>
              )}
              {entry.philology.gender && (
                <span className="border border-stone-200 text-stone-600 text-[8px] px-2.5 py-1.5 font-black uppercase tracking-[0.2em] rounded-sm">
                  {entry.philology.gender}
                </span>
              )}
            </div>
          </div>

          {/* Target Side */}
          <div className="flex-1 min-w-0 w-full md:text-right border-t md:border-t-0 pt-8 md:pt-0">
            <span className="text-[9px] uppercase tracking-[0.4em] text-stone-400 font-black block mb-4">Target ({entry.targetLang.substring(0, 3)})</span>
            <div className="flex items-start md:flex-row-reverse justify-between md:justify-start gap-4">
              <h2 className="text-4xl sm:text-5xl md:text-6xl lg:text-8xl serif font-black tracking-tighter lowercase leading-none text-[#7c1a1a] overflow-wrap-anywhere break-words flex-1 min-w-0 md:text-right">
                {entry.mainTranslation}
              </h2>
              <button 
                onClick={() => handleSpeak(entry.mainTranslation, entry.targetLang, false)} 
                title="Pronounce"
                className="text-stone-300 hover:text-[#7c1a1a] transition-all p-2.5 sm:p-3 hover:bg-white rounded-full border border-transparent hover:border-stone-100 shadow-sm flex-shrink-0 mt-1 sm:mt-2"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="sm:w-6 sm:h-6"><path d="M11 5L6 9H2v6h4l5 4V5z"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/></svg>
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Source Synonyms Bar */}
      {entry.synonyms && entry.synonyms.length > 0 && (
        <div className="px-6 md:px-16 py-5 bg-white border-b border-stone-100 flex flex-wrap items-center gap-4 md:gap-8">
          <div className="flex items-center gap-3 flex-shrink-0">
            <span className="text-sm">🔗</span>
            <span className="text-[9px] uppercase tracking-[0.3em] text-stone-400 font-black">Synonyms</span>
          </div>
          <div className="flex flex-wrap gap-x-4 gap-y-2">
            {entry.synonyms.map((syn, i) => (
              <button
                key={i}
                onClick={() => onSearchTerm?.(syn)}
                className="text-sm sm:text-base font-sans font-bold text-stone-700 hover:text-[#7c1a1a] transition-colors border-b border-transparent hover:border-[#7c1a1a]/20 overflow-wrap-anywhere break-words"
              >
                {syn}{i < entry.synonyms.length - 1 && ","}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Main Content Grid */}
      <div className="flex flex-col lg:grid lg:grid-cols-12">
        <div className="lg:col-span-7 p-6 sm:p-8 md:p-16 space-y-12 md:space-y-16 order-2 lg:order-1 border-b lg:border-b-0 lg:border-r border-stone-100">
          <section>
            <h3 className="text-[10px] uppercase tracking-[0.4em] text-stone-900 font-black mb-8 flex items-center gap-3">
              <span className="text-base">📚</span>
              Literature
            </h3>
            <div className="space-y-10">
              {entry.literature && entry.literature.length > 0 ? (
                entry.literature.map((lit, i) => (
                  <div key={i} className="relative pl-6 border-l-2 border-stone-100 group">
                    <p className="text-xl sm:text-2xl md:text-3xl serif font-medium text-stone-900 mb-3 leading-tight overflow-wrap-anywhere break-words">"{lit.text}"</p>
                    {lit.translation && <p className="text-base sm:text-lg italic text-stone-400 mb-4 leading-relaxed overflow-wrap-anywhere break-words">{lit.translation}</p>}
                    <div className="text-[9px] uppercase tracking-[0.2em] font-black text-stone-500 flex items-center gap-2 flex-wrap">
                      <span className="text-[#7c1a1a]">{lit.author || 'Anonymous'}</span>
                      <span className="text-stone-200">/</span>
                      <span className="italic overflow-wrap-anywhere break-words">{lit.source}</span>
                    </div>
                  </div>
                ))
              ) : (
                <div className="space-y-6">
                  <Shimmer className="h-6 w-full" />
                  <Shimmer className="h-6 w-3/4" />
                </div>
              )}
            </div>
          </section>

          <section>
            <h3 className="text-[10px] uppercase tracking-[0.4em] text-stone-900 font-black mb-6 flex items-center gap-3">
              <span className="text-base">🔬</span>
              Etymology
            </h3>
            <div className="bg-stone-50/50 p-6 md:p-8 border border-stone-100/50 rounded-sm">
              {entry.philology.etymology ? (
                <p className="text-lg sm:text-xl md:text-2xl serif italic text-stone-700 leading-relaxed overflow-wrap-anywhere break-words">
                  {entry.philology.etymology}
                </p>
              ) : <Shimmer className="h-20 w-full" />}
            </div>
          </section>
        </div>

        <div className="lg:col-span-5 bg-[#fcfcfb] p-6 sm:p-8 md:p-16 space-y-12 md:space-y-16 order-1 lg:order-2">
          {/* Target Variations Section */}
          <section>
            <h3 className="text-[10px] uppercase tracking-[0.4em] text-[#7c1a1a] font-black mb-6 flex items-center gap-3">
              <span className="text-base">🔁</span>
              Variations
            </h3>
            <div className="grid grid-cols-1 gap-3">
              {entry.variations.map((v, i) => (
                <div 
                  key={i} 
                  onClick={() => handleSpeak(v.text, entry.targetLang, false)}
                  className="bg-white border border-stone-200/60 p-4 sm:p-6 rounded-sm flex justify-between items-start group hover:border-[#7c1a1a] hover:shadow-lg transition-all cursor-pointer min-w-0"
                >
                  <span className="text-xl sm:text-2xl serif text-stone-900 group-hover:text-[#7c1a1a] transition-colors lowercase tracking-tighter overflow-wrap-anywhere break-words flex-1 pr-4">
                    {v.text}
                  </span>
                  <span className="text-[10px] font-black text-stone-300 group-hover:text-[#7c1a1a] transition-colors uppercase tracking-widest flex-shrink-0 mt-1.5">
                    {Math.round(v.confidence * 100)}%
                  </span>
                </div>
              ))}
            </div>
          </section>

          <section>
            <h3 className="text-[10px] uppercase tracking-[0.4em] text-stone-900 font-black mb-6 flex items-center gap-3">
              <span className="text-base">🗣</span>
              Idioms & Usage
            </h3>
            <div className="space-y-4">
              {displayIdioms.length > 0 ? (
                displayIdioms.map((snt, i) => (
                  <div key={i} className="bg-white p-6 md:p-8 border border-stone-100 shadow-sm rounded-sm relative group">
                    <div className="absolute left-0 top-0 bottom-0 w-1 bg-[#7c1a1a] opacity-0 group-hover:opacity-100 transition-opacity"></div>
                    <p className="text-xl sm:text-2xl serif font-black text-stone-900 mb-1 leading-tight overflow-wrap-anywhere break-words">"{snt.text}"</p>
                    <p className="text-base sm:text-lg serif italic text-[#7c1a1a] mb-3 overflow-wrap-anywhere break-words">{snt.translation}</p>
                    <p className="text-[8px] text-stone-400 uppercase tracking-widest font-bold overflow-wrap-anywhere break-words">{snt.context}</p>
                  </div>
                ))
              ) : <Shimmer className="h-32 w-full" />}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default ResultCard;

import React, { useState, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWordCore, enrichLexicalEntry } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import { triggerHaptic } from '../services/telegram';
import { normalizeQuery } from '../utils/normalization';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS',
  Arabic: 'ARA'
};

const LANGUAGES_LIST: Language[] = ['German', 'Uzbek', 'English', 'Russian', 'Arabic'];

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  selectedEntry,
  onEntryClick,
  onStartArena
}) => {
  const [query, setQuery] = useState('');

  const [sourceLang, setSourceLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexSourceLang');
    return (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'German');
  });

  const [targetLang, setTargetLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexTargetLang');
    const initialTarget = (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'Uzbek');
    const initialSource = localStorage.getItem('lexSourceLang') || 'German';
    return (initialTarget === initialSource) ? (initialSource === 'Uzbek' ? 'German' : 'Uzbek') : initialTarget;
  });

  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [voiceSupported, setVoiceSupported] = useState(true);
  const [voiceStatusMsg, setVoiceStatusMsg] = useState<string | null>(null);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [needsKeySelection, setNeedsKeySelection] = useState(false);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const currentSearchIdRef = useRef<string | null>(null);

  const handleSourceChange = (newLang: Language) => {
    if (newLang === targetLang) {
      setTargetLang(sourceLang);
      localStorage.setItem('lexTargetLang', sourceLang);
    }
    setSourceLang(newLang);
    localStorage.setItem('lexSourceLang', newLang);
    triggerHaptic('light');
  };

  const handleTargetChange = (newLang: Language) => {
    if (newLang === sourceLang) {
      setSourceLang(targetLang);
      localStorage.setItem('lexSourceLang', targetLang);
    }
    setTargetLang(newLang);
    localStorage.setItem('lexTargetLang', newLang);
    triggerHaptic('light');
  };

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setVoiceSupported(false);
    }
  }, []);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      setShowSuggestions(false);
      localStorage.setItem('lexSourceLang', selectedEntry.sourceLang);
      localStorage.setItem('lexTargetLang', selectedEntry.targetLang);
      currentSearchIdRef.current = selectedEntry.id;
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    if (loading) {
      setShowSuggestions(false);
      setSuggestions([]);
      return;
    }

    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim();
      if (trimmedQuery.length >= 2) {
        const normSearch = normalizeQuery(trimmedQuery, sourceLang);

        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && normalizeQuery(e.term, e.sourceLang).startsWith(normSearch))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && normalizeQuery(e.term, sourceLang).startsWith(normSearch))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(normSearch, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {}

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        if (!loading && !(result && normalizeQuery(result.term, sourceLang) === normSearch)) {
          setSuggestions(unique);
          setShowSuggestions(unique.length > 0);
          setSelectedIndex(-1);
        }
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history, loading, result]);

  const startVoiceSearch = async () => {
    await resumeAudioContext().catch(() => {});
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    if (!SpeechRecognition) {
      setVoiceStatusMsg("Voice access restricted");
      triggerHaptic('error');
      setTimeout(() => setVoiceStatusMsg(null), 3000);
      return;
    }

    const recognition = new SpeechRecognition();
    const langCodes: Record<Language, string> = {
      German: 'de-DE', Uzbek: 'uz-UZ', English: 'en-US', Russian: 'ru-RU', Arabic: 'ar-SA'
    };

    recognition.lang = langCodes[sourceLang];
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => { setIsListening(true); triggerHaptic('light'); };
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setQuery(transcript);
      handleSearch(transcript);
    };
    recognition.onerror = () => { setIsListening(false); triggerHaptic('error'); };
    recognition.onend = () => setIsListening(false);

    try { recognition.start(); } catch (e) { setIsListening(false); }
  };

  const handleOpenKeySelector = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      triggerHaptic('heavy');
      await (window as any).aistudio.openSelectKey();
      setNeedsKeySelection(false);
      handleSearch();
    } else {
      window.open('https://ai.google.dev/gemini-api/docs/billing', '_blank');
    }
  };

  const handleSearch = async (overrideQuery?: string) => {
    await resumeAudioContext().catch(() => {});

    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setShowSuggestions(false);
    setSearchError(null);
    setNeedsKeySelection(false);

    if (inputRef.current) inputRef.current.blur();

    const normQuery = normalizeQuery(cleanQuery, sourceLang);
    setQuery(cleanQuery);

    const searchId = Math.random().toString(36).substring(7);
    currentSearchIdRef.current = searchId;

    const localHit = history.find(e => 
      normalizeQuery(e.term, e.sourceLang) === normQuery && 
      e.sourceLang === sourceLang && 
      e.targetLang === targetLang
    );

    if (localHit) {
      setResult(localHit);
      if (autoAudio) {
        speak(cleanQuery, sourceLang, localHit.sourceAudio).then((sourceAudio) => {
          if (currentSearchIdRef.current === searchId) {
            speak(localHit.mainTranslation, targetLang, localHit.targetAudio).then((targetAudio) => {
              // Even for local hits, if we somehow got new audio (e.g. source was cached but target wasn't)
              if ((sourceAudio && !localHit.sourceAudio) || (targetAudio && !localHit.targetAudio)) {
                const updated = { ...localHit };
                if (sourceAudio) updated.sourceAudio = sourceAudio;
                if (targetAudio) updated.targetAudio = targetAudio;
                onEntrySaved(updated);
              }
            });
          }
        }).catch(() => {});
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);

      if (currentSearchIdRef.current !== searchId) return;

      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          speak(cleanQuery, sourceLang, globalHit.sourceAudio).then((sourceAudio) => {
            if (currentSearchIdRef.current === searchId) {
              speak(globalHit.mainTranslation, targetLang, globalHit.targetAudio).then((targetAudio) => {
                if ((sourceAudio && !globalHit.sourceAudio) || (targetAudio && !globalHit.targetAudio)) {
                  const updated = { ...globalHit };
                  if (sourceAudio) updated.sourceAudio = sourceAudio;
                  if (targetAudio) updated.targetAudio = targetAudio;
                  onEntrySaved(updated);
                  saveGlobalEntry(updated);
                }
              });
            }
          }).catch(() => {});
        }
        return;
      }

      const coreEntry = await translateWordCore(cleanQuery, sourceLang, targetLang);
      if (currentSearchIdRef.current !== searchId) return;

      coreEntry.normalizedTerm = normQuery;
      setResult(coreEntry);
      setLoading(false);

      if (autoAudio) {
        speak(cleanQuery, sourceLang).then((sourceAudio) => {
          if (currentSearchIdRef.current === searchId) {
            speak(coreEntry.mainTranslation, targetLang).then((targetAudio) => {
              if (sourceAudio) coreEntry.sourceAudio = sourceAudio;
              if (targetAudio) coreEntry.targetAudio = targetAudio;
              onEntrySaved(coreEntry);
            });
          }
        }).catch(() => {});
      } else {
        onEntrySaved(coreEntry);
      }

      enrichLexicalEntry(coreEntry).then(enrichment => {
        if (currentSearchIdRef.current === searchId) {
          const fullEntry = { ...coreEntry, ...enrichment };
          setResult(fullEntry);
          onEntrySaved(fullEntry);
          saveGlobalEntry(fullEntry);
        }
      }).catch(e => console.error("Philological enrichment failed", e));

    } catch (err: any) {
      if (currentSearchIdRef.current !== searchId) return;
      console.error("Philological retrieval failure:", err);
      if (err.message?.includes("ENTITY_NOT_FOUND") || err.message?.includes("NOT_FOUND")) {
        setSearchError("Linguistic node unavailable in this project region.");
        setNeedsKeySelection(true);
      } else if (err.message?.includes("PERMISSION_DENIED")) {
        setSearchError("Archival access denied. Please verify your selected project key.");
        setNeedsKeySelection(true);
      } else {
        setSearchError("The archive is silent. Network failure or API limitations on iOS.");
      }
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      setShowSuggestions(false);
      if (showSuggestions && selectedIndex >= 0) {
        const selectedTerm = suggestions[selectedIndex].term;
        setQuery(selectedTerm);
        handleSearch(selectedTerm);
      } else {
        handleSearch();
      }
      return;
    }

    if (!showSuggestions) return;
    if (e.key === 'ArrowDown') { e.preventDefault(); setSelectedIndex(prev => (prev + 1) % suggestions.length); }
    else if (e.key === 'ArrowUp') { e.preventDefault(); setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length); }
    else if (e.key === 'Escape') { setShowSuggestions(false); }
  };

  return (
    <div className="space-y-8 md:space-y-16 max-w-7xl mx-auto contain-layout">
      {/* Search Header Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-[3px] border-[#7c1a1a] pl-4">
            <span className="text-[9px] uppercase tracking-[0.4em] text-stone-500 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl md:text-3xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[8px] uppercase tracking-[0.2em] text-stone-400 font-bold">Total XP</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-4 bg-stone-100/50 p-2 rounded-sm w-full sm:w-auto border border-stone-200">
             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full} 
                    onClick={() => handleSourceChange(full)} 
                    className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-400 hover:text-stone-700'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full} 
                    onClick={() => handleTargetChange(full)} 
                    className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-400 hover:text-stone-700'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
          </div>
