import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const audioBufferCache = new Map<string, AudioBuffer>();
let sharedAudioCtx: AudioContext | null = null;
let isResuming = false;

// BCP 47 Language Mapping for Native Synthesis
const NATIVE_LANG_CODES: Record<string, string> = {
  'German': 'de-DE',
  'English': 'en-US',
  'Arabic': 'ar-SA',
  'Russian': 'ru-RU'
};

/**
 * Standardizes the AudioContext retrieval.
 */
export function getAudioContext() {
  if (!sharedAudioCtx) {
    const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
    if (AudioContextClass) {
      sharedAudioCtx = new AudioContextClass({ sampleRate: 24000 });
    }
  }
  return sharedAudioCtx;
}

/**
 * Robustly resumes the AudioContext within a user gesture.
 */
export async function resumeAudioContext(): Promise<void> {
  const ctx = getAudioContext();
  if (!ctx || isResuming) return;

  if (ctx.state === 'running') return;

  isResuming = true;
  try {
    await ctx.resume();
    const buffer = ctx.createBuffer(1, 1, 24000);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  } catch (e) {
    // Silent catch
  } finally {
    isResuming = false;
  }
}

/**
 * Decodes base64 pcm data.
 */
function decode(base64: string): Uint8Array {
  const normalized = base64.replace(/[^A-Za-z0-9+/=]/g, "");
  try {
    const binaryString = atob(normalized);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  } catch (e) {
    console.error("Base64 decoding failed", e);
    return new Uint8Array(0);
  }
}

/**
 * Decodes raw PCM bytes to AudioBuffer.
 */
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

/**
 * Uses browser's built-in SpeechSynthesis.
 */
async function speakNative(text: string, lang: Language): Promise<boolean> {
  const code = NATIVE_LANG_CODES[lang];
  if (!code || !window.speechSynthesis) return false;

  return new Promise((resolve) => {
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = code;

    // Attempt to pick a high-quality local voice
    const voices = window.speechSynthesis.getVoices();
    const voice = voices.find(v => v.lang.startsWith(code) && v.localService) || 
                  voices.find(v => v.lang.startsWith(code));
    if (voice) utterance.voice = voice;

    utterance.onend = () => resolve(true);
    utterance.onerror = () => resolve(false);
    window.speechSynthesis.speak(utterance);

    // In case of silent error/stuck, resolve after timeout
    setTimeout(() => resolve(true), 5000);
  });
}

/**
 * Synthesizes and plays text. 
 * Prioritizes Native TTS for supported languages.
 * Fallback to Gemini for Uzbek or when Native fails.
 * Returns generated base64 data if cached/created.
 */
export async function speak(text: string, lang: Language, existingData?: string): Promise<string | undefined> {
  if (!text || !text.trim()) return;

  const ctx = getAudioContext();
  if (!ctx) return;

  const playBuffer = (buffer: AudioBuffer) => {
    if (ctx.state !== 'running') ctx.resume().catch(() => {});
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  };

  // 1. Play existing cached audio data if provided
  if (existingData) {
    try {
      const cacheKey = `data:${existingData.substring(0, 32)}`;
      let buffer = audioBufferCache.get(cacheKey);
      if (!buffer) {
        buffer = await decodeAudioData(decode(existingData), ctx, 24000, 1);
        audioBufferCache.set(cacheKey, buffer);
      }
      playBuffer(buffer);
      return existingData;
    } catch (e) {
      console.warn("Cached audio playback failed, falling back.");
    }
  }

  // 2. Use Native TTS for German, English, Arabic, Russian
  if (NATIVE_LANG_CODES[lang]) {
    const success = await speakNative(text, lang);
    if (success) return undefined; // No data returned for native
  }

  // 3. Use Gemini API for Uzbek or fallback
  const memoryCacheKey = `${text.trim()}:${lang}`;
  if (audioBufferCache.has(memoryCacheKey)) {
    playBuffer(audioBufferCache.get(memoryCacheKey)!);
    return undefined;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const voiceName = VOICE_MAPPING[lang] || 'Puck';

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say clearly: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
    audioBufferCache.set(memoryCacheKey, audioBuffer);
    playBuffer(audioBuffer);

    return base64Audio;
  } catch (error) {
    console.error("TTS Engine Failure:", error);
    return undefined;
  }
}

import React from 'react';
