    if (generatedAudio && !existingAudio && onUpdateEntry) {
      const updatedEntry = { ...entry };
      if (isSource) updatedEntry.sourceAudio = generatedAudio;
      else updatedEntry.targetAudio = generatedAudio;
      onUpdateEntry(updatedEntry);
