                  {entry.philology.etymology}
                </p>
              ) : <Shimmer className="h-20 w-full" />}
            </div>
          </section>
        </div>

        <div className="lg:col-span-5 bg-[#fcfcfb] p-6 sm:p-8 md:p-16 space-y-12 md:space-y-16 order-1 lg:order-2">
          {/* Target Variations Section */}
          <section>
            <h3 className="text-[10px] uppercase tracking-[0.4em] text-[#7c1a1a] font-black mb-6 flex items-center gap-3">
              <span className="text-base">🔁</span>
              Variations
            </h3>
            <div className="grid grid-cols-1 gap-3">
              {entry.variations.map((v, i) => (
                <div 
                  key={i} 
                  onClick={() => handleSpeak(v.text, entry.targetLang, false)}
                  className="bg-white border border-stone-200/60 p-4 sm:p-6 rounded-sm flex justify-between items-start group hover:border-[#7c1a1a] hover:shadow-lg transition-all cursor-pointer min-w-0"
                >
                  <span className="text-xl sm:text-2xl serif text-stone-900 group-hover:text-[#7c1a1a] transition-colors lowercase tracking-tighter overflow-wrap-anywhere break-words flex-1 pr-4">
                    {v.text}
                  </span>
                  <span className="text-[10px] font-black text-stone-300 group-hover:text-[#7c1a1a] transition-colors uppercase tracking-widest flex-shrink-0 mt-1.5">
                    {Math.round(v.confidence * 100)}%
                  </span>
                </div>
              ))}
            </div>
          </section>

          <section>
            <h3 className="text-[10px] uppercase tracking-[0.4em] text-stone-900 font-black mb-6 flex items-center gap-3">
              <span className="text-base">🗣</span>
              Idioms & Usage
            </h3>
            <div className="space-y-4">
              {displayIdioms.length > 0 ? (
                displayIdioms.map((snt, i) => (
                  <div key={i} className="bg-white p-6 md:p-8 border border-stone-100 shadow-sm rounded-sm relative group">
                    <div className="absolute left-0 top-0 bottom-0 w-1 bg-[#7c1a1a] opacity-0 group-hover:opacity-100 transition-opacity"></div>
                    <p className="text-xl sm:text-2xl serif font-black text-stone-900 mb-1 leading-tight overflow-wrap-anywhere break-words">"{snt.text}"</p>
                    <p className="text-base sm:text-lg serif italic text-[#7c1a1a] mb-3 overflow-wrap-anywhere break-words">{snt.translation}</p>
                    <p className="text-[8px] text-stone-400 uppercase tracking-widest font-bold overflow-wrap-anywhere break-words">{snt.context}</p>
                  </div>
                ))
              ) : <Shimmer className="h-32 w-full" />}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default ResultCard;

import React, { useState, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWordCore, enrichLexicalEntry } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import { triggerHaptic } from '../services/telegram';
import { normalizeQuery } from '../utils/normalization';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS',
  Arabic: 'ARA'
};

const LANGUAGES_LIST: Language[] = ['German', 'Uzbek', 'English', 'Russian', 'Arabic'];

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  selectedEntry,
  onEntryClick,
  onStartArena
}) => {
  const [query, setQuery] = useState('');

  const [sourceLang, setSourceLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexSourceLang');
    return (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'German');
  });

  const [targetLang, setTargetLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexTargetLang');
    const initialTarget = (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'Uzbek');
    const initialSource = localStorage.getItem('lexSourceLang') || 'German';
    return (initialTarget === initialSource) ? (initialSource === 'Uzbek' ? 'German' : 'Uzbek') : initialTarget;
  });

  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [voiceSupported, setVoiceSupported] = useState(true);
  const [voiceStatusMsg, setVoiceStatusMsg] = useState<string | null>(null);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [needsKeySelection, setNeedsKeySelection] = useState(false);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const currentSearchIdRef = useRef<string | null>(null);

  const handleSourceChange = (newLang: Language) => {
    if (newLang === targetLang) {
      setTargetLang(sourceLang);
      localStorage.setItem('lexTargetLang', sourceLang);
    }
    setSourceLang(newLang);
    localStorage.setItem('lexSourceLang', newLang);
    triggerHaptic('light');
  };

  const handleTargetChange = (newLang: Language) => {
    if (newLang === sourceLang) {
      setSourceLang(targetLang);
      localStorage.setItem('lexSourceLang', targetLang);
    }
    setTargetLang(newLang);
    localStorage.setItem('lexTargetLang', newLang);
    triggerHaptic('light');
  };

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setVoiceSupported(false);
    }
  }, []);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      setShowSuggestions(false);
      localStorage.setItem('lexSourceLang', selectedEntry.sourceLang);
      localStorage.setItem('lexTargetLang', selectedEntry.targetLang);
      currentSearchIdRef.current = selectedEntry.id;
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    if (loading) {
      setShowSuggestions(false);
      setSuggestions([]);
      return;
    }

    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim();
      if (trimmedQuery.length >= 2) {
        const normSearch = normalizeQuery(trimmedQuery, sourceLang);

        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && normalizeQuery(e.term, e.sourceLang).startsWith(normSearch))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && normalizeQuery(e.term, sourceLang).startsWith(normSearch))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(normSearch, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {}

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        if (!loading && !(result && normalizeQuery(result.term, sourceLang) === normSearch)) {
          setSuggestions(unique);
          setShowSuggestions(unique.length > 0);
          setSelectedIndex(-1);
        }
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history, loading, result]);

  const startVoiceSearch = async () => {
    await resumeAudioContext().catch(() => {});
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    if (!SpeechRecognition) {
      setVoiceStatusMsg("Voice access restricted");
      triggerHaptic('error');
      setTimeout(() => setVoiceStatusMsg(null), 3000);
      return;
    }

    const recognition = new SpeechRecognition();
    const langCodes: Record<Language, string> = {
      German: 'de-DE', Uzbek: 'uz-UZ', English: 'en-US', Russian: 'ru-RU', Arabic: 'ar-SA'
    };

    recognition.lang = langCodes[sourceLang];
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => { setIsListening(true); triggerHaptic('light'); };
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setQuery(transcript);
      handleSearch(transcript);
    };
    recognition.onerror = () => { setIsListening(false); triggerHaptic('error'); };
    recognition.onend = () => setIsListening(false);

    try { recognition.start(); } catch (e) { setIsListening(false); }
  };

  const handleOpenKeySelector = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      triggerHaptic('heavy');
      await (window as any).aistudio.openSelectKey();
      setNeedsKeySelection(false);
      handleSearch();
    } else {
      window.open('https://ai.google.dev/gemini-api/docs/billing', '_blank');
    }
  };

  const handleSearch = async (overrideQuery?: string) => {
    await resumeAudioContext().catch(() => {});

    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setShowSuggestions(false);
    setSearchError(null);
    setNeedsKeySelection(false);

    if (inputRef.current) inputRef.current.blur();

    const normQuery = normalizeQuery(cleanQuery, sourceLang);
    setQuery(cleanQuery);

    const searchId = Math.random().toString(36).substring(7);
    currentSearchIdRef.current = searchId;

    const localHit = history.find(e => 
      normalizeQuery(e.term, e.sourceLang) === normQuery && 
      e.sourceLang === sourceLang && 
      e.targetLang === targetLang
    );

    if (localHit) {
      setResult(localHit);
      if (autoAudio) {
        const sourceData = await speak(cleanQuery, sourceLang, localHit.sourceAudio);
        if (currentSearchIdRef.current === searchId) {
          const targetData = await speak(localHit.mainTranslation, targetLang, localHit.targetAudio);
          // Sync audio updates if generated
          if ((sourceData && !localHit.sourceAudio) || (targetData && !localHit.targetAudio)) {
            const updated = { ...localHit };
            if (sourceData) updated.sourceAudio = sourceData;
            if (targetData) updated.targetAudio = targetData;
            onEntrySaved(updated);
          }
        }
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);

      if (currentSearchIdRef.current !== searchId) return;

      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          const sourceData = await speak(cleanQuery, sourceLang, globalHit.sourceAudio);
          if (currentSearchIdRef.current === searchId) {
            const targetData = await speak(globalHit.mainTranslation, targetLang, globalHit.targetAudio);
            if ((sourceData && !globalHit.sourceAudio) || (targetData && !globalHit.targetAudio)) {
              const updated = { ...globalHit };
              if (sourceData) updated.sourceAudio = sourceData;
              if (targetData) updated.targetAudio = targetData;
              onEntrySaved(updated);
              saveGlobalEntry(updated);
            }
          }
        }
        return;
      }

      const coreEntry = await translateWordCore(cleanQuery, sourceLang, targetLang);
      if (currentSearchIdRef.current !== searchId) return;

      coreEntry.normalizedTerm = normQuery;
      setResult(coreEntry);
      setLoading(false);

      if (autoAudio) {
        const sourceData = await speak(cleanQuery, sourceLang);
        if (currentSearchIdRef.current === searchId) {
          const targetData = await speak(coreEntry.mainTranslation, targetLang);
          if (sourceData) coreEntry.sourceAudio = sourceData;
          if (targetData) coreEntry.targetAudio = targetData;
          onEntrySaved(coreEntry);
        }
      } else {
        onEntrySaved(coreEntry);
      }

      enrichLexicalEntry(coreEntry).then(enrichment => {
        if (currentSearchIdRef.current === searchId) {
          const fullEntry = { ...coreEntry, ...enrichment };
          setResult(fullEntry);
          onEntrySaved(fullEntry);
          saveGlobalEntry(fullEntry);
        }
      }).catch(e => console.error("Philological enrichment failed", e));

    } catch (err: any) {
      if (currentSearchIdRef.current !== searchId) return;
      console.error("Philological retrieval failure:", err);
      if (err.message?.includes("ENTITY_NOT_FOUND") || err.message?.includes("NOT_FOUND")) {
        setSearchError("Linguistic node unavailable in this project region.");
        setNeedsKeySelection(true);
      } else if (err.message?.includes("PERMISSION_DENIED")) {
        setSearchError("Archival access denied. Please verify your selected project key.");
        setNeedsKeySelection(true);
      } else {
        setSearchError("The archive is silent. Network failure or API limitations on iOS.");
      }
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      setShowSuggestions(false);
      if (showSuggestions && selectedIndex >= 0) {
        const selectedTerm = suggestions[selectedIndex].term;
        setQuery(selectedTerm);
        handleSearch(selectedTerm);
      } else {
        handleSearch();
      }
      return;
    }

    if (!showSuggestions) return;
    if (e.key === 'ArrowDown') { e.preventDefault(); setSelectedIndex(prev => (prev + 1) % suggestions.length); }
    else if (e.key === 'ArrowUp') { e.preventDefault(); setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length); }
    else if (e.key === 'Escape') { setShowSuggestions(false); }
  };

  return (
    <div className="space-y-8 md:space-y-16 max-w-7xl mx-auto contain-layout">
      {/* Search Header Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-[3px] border-[#7c1a1a] pl-4">
            <span className="text-[9px] uppercase tracking-[0.4em] text-stone-500 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl md:text-3xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[8px] uppercase tracking-[0.2em] text-stone-400 font-bold">Total XP</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-4 bg-stone-100/50 p-2 rounded-sm w-full sm:w-auto border border-stone-200">
             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full} 
                    onClick={() => handleSourceChange(full)} 
                    className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-400 hover:text-stone-700'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full} 
                    onClick={() => handleTargetChange(full)} 
                    className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-400 hover:text-stone-700'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <button onClick={() => { setAutoAudio(!autoAudio); triggerHaptic('light'); }} className={`flex items-center gap-4 px-5 py-2.5 rounded-full border transition-all ${autoAudio ? 'bg-[#7c1a1a]/5 border-[#7c1a1a]/40' : 'bg-stone-50 border-stone-200'}`}>
            <span className={`text-[11px] uppercase tracking-[0.2em] font-black ${autoAudio ? 'text-[#7c1a1a]' : 'text-stone-500'}`}>AUTO-AUDIO</span>
            <div className={`w-3.5 h-3.5 rounded-full ${autoAudio ? 'bg-[#7c1a1a] shadow-[0_0_10px_rgba(124,26,26,0.4)]' : 'bg-stone-300'}`} />
          </button>
        </div>
      </div>

      {/* Search Input Area */}
      <div className="relative w-full" ref={suggestionRef}>
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }}>
          <div className={`bg-white border-2 transition-all rounded-sm overflow-hidden flex items-stretch min-h-[70px] md:min-h-[110px] ${isListening ? 'border-[#7c1a1a] ring-8 ring-[#7c1a1a]/5' : 'border-stone-200 shadow-md focus-within:border-stone-400 focus-within:shadow-lg'}`}>
            <input 
              ref={inputRef}
              type="text" 
              value={query} 
              onChange={(e) => setQuery(e.target.value)} 
              onFocus={() => { if (suggestions.length > 0 && !loading) setShowSuggestions(true); }}
              onKeyDown={handleKeyDown}
              spellCheck={false}
              autoCapitalize="none"
              autoComplete="off"
              autoCorrect="off"
              placeholder={isListening ? "Listening..." : voiceStatusMsg || "Summon an inscription..."}
              className={`flex-1 min-w-0 px-6 md:px-10 text-2xl md:text-6xl serif bg-transparent outline-none text-stone-900 lowercase transition-all ${isListening ? 'placeholder:text-[#7c1a1a]/40' : voiceStatusMsg ? 'placeholder:text-[#7c1a1a]' : 'placeholder:text-stone-200'}`} 
            />

            <div className="flex flex-shrink-0 items-stretch border-l-2 border-stone-50">
              <button 
                type="button" 
                onClick={startVoiceSearch}
                className={`px-4 md:px-8 transition-all flex items-center justify-center border-r border-stone-50 ${isListening ? 'text-[#7c1a1a] bg-[#7c1a1a]/5' : !voiceSupported ? 'text-stone-200 cursor-not-allowed' : 'text-stone-400 hover:text-[#7c1a1a]'}`}
              >
                <div className="relative">
                  {isListening && <div className="absolute -inset-2 border-2 border-[#7c1a1a]/20 rounded-full animate-ping"></div>}
                  <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 md:w-9 md:h-9" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/>
                  </svg>
                </div>
              </button>

              <button 
                type="submit" 
                disabled={loading} 
                className={`px-5 md:px-10 transition-all flex items-center justify-center ${loading ? 'bg-stone-50' : 'bg-white hover:bg-[#7c1a1a]/5 text-[#7c1a1a]'}`}
              >
                {loading ? (
                  <div className="w-8 h-8 border-4 border-[#7c1a1a] border-t-transparent rounded-full animate-spin" />
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8 md:w-12 md:h-12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round">
                    <line x1="5" y1="12" x2="19" y2="12"></line>
                    <polyline points="12 5 19 12 12 19"></polyline>
                  </svg>
                )}
              </button>
            </div>
          </div>
        </form>

        {showSuggestions && !loading && (
          <div className="absolute top-full left-0 right-0 bg-white border-2 border-stone-200 shadow-2xl z-20 rounded-b-sm overflow-hidden animate-in fade-in slide-in-from-top-2">
             {suggestions.map((s, idx) => (
               <button 
                 key={idx} 
                 onClick={() => { setQuery(s.term); handleSearch(s.term); }}
                 className={`w-full text-left px-10 py-6 border-b border-stone-100 last:border-0 flex items-center justify-between transition-colors ${selectedIndex === idx ? 'bg-stone-50' : 'hover:bg-stone-50/50'}`}
               >
                 <span className="serif text-2xl md:text-3xl text-stone-700">{s.term}</span>
                 <span className="text-[9px] uppercase tracking-widest font-black text-stone-300">{s.source}</span>
               </button>
             ))}
          </div>
        )}
      </div>

      {/* Results Rendering */}
      <div className="min-h-[60px]">
        {loading && (
          <div className="bg-white border border-stone-100 p-16 flex flex-col items-center justify-center space-y-8">
            <div className="w-20 h-20 border-[5px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin"></div>
            <p className="serif text-3xl italic text-stone-300">Consulting the Lexicon...</p>
          </div>
        )}

        {searchError && (
          <div className="bg-[#7c1a1a] text-stone-100 p-12 md:p-20 rounded-sm shadow-xl animate-in zoom-in-95 duration-500">
             <div className="flex flex-col md:flex-row items-center gap-8">
                <div className="p-6 bg-white/10 rounded-full">
                  <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
                </div>
                <div className="flex-1 text-center md:text-left">
                  <h3 className="text-3xl md:text-5xl serif font-black mb-4">The Archive is Silent.</h3>
                  <p className="text-stone-300 serif italic text-xl md:text-2xl mb-8 opacity-80">{searchError}</p>

                  <div className="flex flex-wrap gap-4 justify-center md:justify-start">
                    <button 
                      onClick={() => handleSearch()}
                      className="px-10 py-4 bg-white text-[#7c1a1a] text-[11px] font-black uppercase tracking-[0.4em] hover:bg-stone-100 transition-all rounded-sm shadow-lg active:scale-95"
                    >
                      Retry Invocation
                    </button>
                    {needsKeySelection && (
                      <button 
                        onClick={handleOpenKeySelector}
                        className="px-10 py-4 border-2 border-white text-white text-[11px] font-black uppercase tracking-[0.4em] hover:bg-white/10 transition-all rounded-sm active:scale-95"
                      >
                        Select Archival Key
                      </button>
                    )}
                  </div>
                </div>
             </div>
          </div>
        )}

        {result && <ResultCard entry={result} onSearchTerm={(term) => handleSearch(term)} onUpdateEntry={onEntrySaved} />}
      </div>

      <div className="pt-16 md:pt-32 border-t border-stone-100">
        <div className="flex justify-between items-center mb-12">
          <div className="border-l-[4px] border-[#7c1a1a] pl-8 py-1">
            <h2 className="text-[14px] uppercase tracking-[0.6em] text-stone-900 font-black">Archival Chronicles</h2>
          </div>
        </div>
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

export default Dictionary;

import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const audioBufferCache = new Map<string, AudioBuffer>();
let sharedAudioCtx: AudioContext | null = null;
let isResuming = false;

// BCP 47 Language Mapping for Native Synthesis
const NATIVE_LANG_CODES: Record<string, string> = {
  'German': 'de-DE',
  'English': 'en-US',
  'Arabic': 'ar-SA',
  'Russian': 'ru-RU'
};

/**
 * Standardizes the AudioContext retrieval.
