function getHighQualityVoice(code: string): SpeechSynthesisVoice | null {
  const voices = window.speechSynthesis.getVoices();
  const langVoices = voices.filter(v => v.lang.replace('_', '-').startsWith(code));

  if (langVoices.length === 0) return null;

  // 1. Prioritize "Google" voices (usually high-quality network voices)
  // 2. Prioritize "Premium" or "Enhanced" (Apple/iOS high quality)
  // 3. Prioritize non-local service (often better)
  // 4. Avoid "Compact"

  const googleVoice = langVoices.find(v => v.name.includes("Google") && !v.name.includes("Compact"));
  if (googleVoice) return googleVoice;

  const premiumVoice = langVoices.find(v => (v.name.includes("Premium") || v.name.includes("Enhanced")) && !v.name.includes("Compact"));
  if (premiumVoice) return premiumVoice;

  const siriVoice = langVoices.find(v => v.name.includes("Siri"));
  if (siriVoice) return siriVoice;

  // Fallback to any voice that isn't "Compact"
  return langVoices.find(v => !v.name.toLowerCase().includes("compact")) || langVoices[0];
