async function speakNative(text: string, lang: Language): Promise<boolean> {
  const code = NATIVE_LANG_CODES[lang];
  if (!code || !window.speechSynthesis) return false;

  return new Promise((resolve) => {
    // If voices aren't loaded yet, we might need to wait for voiceschanged
    // but usually calling it once warms it up.
    let voices = window.speechSynthesis.getVoices();

    const play = () => {
      window.speechSynthesis.cancel();
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = code;

      const voice = getHighQualityVoice(code);
      if (voice) {
        utterance.voice = voice;
      }

      utterance.pitch = 1.0;
      utterance.rate = 1.0; // Standard pace for clarity
      utterance.volume = 1.0;

      utterance.onend = () => resolve(true);
      utterance.onerror = (e) => {
