 * Synthesizes and plays text. 
 * Prioritizes Native TTS for supported languages.
 * Fallback to Gemini for Uzbek or when Native fails.
 * Returns generated base64 data if cached/created.
 */
export async function speak(text: string, lang: Language, existingData?: string): Promise<string | undefined> {
  if (!text || !text.trim()) return;

  const ctx = getAudioContext();
  if (!ctx) return;

  const playBuffer = (buffer: AudioBuffer) => {
    if (ctx.state !== 'running') ctx.resume().catch(() => {});
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  };

