      config: {
        responseModalalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
    audioBufferCache.set(memoryCacheKey, audioBuffer);
    playBuffer(audioBuffer);

    return base64Audio;
  } catch (error) {
    console.error("TTS Engine Failure:", error);
    return undefined;
  }
}

import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const audioBufferCache = new Map<string, AudioBuffer>();
let sharedAudioCtx: AudioContext | null = null;
let isResuming = false;
let isUnlocked = false;

// BCP 47 Language Mapping for Native Synthesis
const NATIVE_LANG_CODES: Record<string, string> = {
  'German': 'de-DE',
  'English': 'en-US',
  'Arabic': 'ar-SA',
  'Russian': 'ru-RU'
};

/**
 * Standardizes the AudioContext retrieval.
 */
export function getAudioContext() {
  if (!sharedAudioCtx) {
    const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
    if (AudioContextClass) {
      // Use 44100 for better hardware compatibility on mobile
      sharedAudioCtx = new AudioContextClass();
    }
  }
  return sharedAudioCtx;
}

/**
 * Robustly resumes the AudioContext within a user gesture.
 * On mobile/iOS, this MUST be called directly in the onClick handler.
 */
export async function resumeAudioContext(): Promise<void> {
  const ctx = getAudioContext();
  if (!ctx || isResuming) return;

  if (ctx.state === 'running' && isUnlocked) return;

  isResuming = true;
  try {
    // Force resume
    await ctx.resume();

    // Play a tiny silent buffer to "unlock" the hardware for the remainder of the session
    const buffer = ctx.createBuffer(1, 1, 22050);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);

    isUnlocked = true;
  } catch (e) {
    console.warn("Audio unlock failed:", e);
  } finally {
    isResuming = false;
  }
}

/**
 * Decodes base64 pcm data.
 */
function decode(base64: string): Uint8Array {
  const normalized = base64.replace(/[^A-Za-z0-9+/=]/g, "");
  try {
    const binaryString = atob(normalized);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  } catch (e) {
    console.error("Base64 decoding failed", e);
    return new Uint8Array(0);
  }
}

/**
 * Decodes raw PCM bytes to AudioBuffer.
 */
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

/**
 * Returns a high-quality voice if available.
 */
function getHighQualityVoice(code: string): SpeechSynthesisVoice | null {
  const voices = window.speechSynthesis.getVoices();
  const langVoices = voices.filter(v => v.lang.replace('_', '-').startsWith(code));

  if (langVoices.length === 0) return null;

  const googleVoice = langVoices.find(v => v.name.includes("Google") && !v.name.includes("Compact"));
  if (googleVoice) return googleVoice;

  const premiumVoice = langVoices.find(v => (v.name.includes("Premium") || v.name.includes("Enhanced")) && !v.name.includes("Compact"));
  if (premiumVoice) return premiumVoice;

  const siriVoice = langVoices.find(v => v.name.includes("Siri"));
  if (siriVoice) return siriVoice;

  return langVoices.find(v => !v.name.toLowerCase().includes("compact")) || langVoices[0];
}

/**
 * Uses browser's built-in SpeechSynthesis with improved voice selection.
 */
async function speakNative(text: string, lang: Language): Promise<boolean> {
  const code = NATIVE_LANG_CODES[lang];
  if (!code || !window.speechSynthesis) return false;

  return new Promise((resolve) => {
    // Cancel any ongoing speech to clear the pipe
    window.speechSynthesis.cancel();

    const startSpeech = () => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = code;

      const voice = getHighQualityVoice(code);
      if (voice) utterance.voice = voice;

      utterance.pitch = 1.0;
      utterance.rate = 1.0; 
      utterance.volume = 1.0;

      // CRITICAL: Keep a global reference to prevent garbage collection on mobile
      (window as any)._currentUtterance = utterance;

      utterance.onend = () => {
        (window as any)._currentUtterance = null;
        resolve(true);
      };

      utterance.onerror = (e) => {
        console.warn("Native synthesis error", e);
        (window as any)._currentUtterance = null;
        resolve(false);
      };

      window.speechSynthesis.speak(utterance);
    };

    // Chrome and Safari sometimes require voices to be loaded
    if (window.speechSynthesis.getVoices().length === 0) {
      window.speechSynthesis.addEventListener('voiceschanged', function listener() {
        window.speechSynthesis.removeEventListener('voiceschanged', listener);
        startSpeech();
      });
      // Safety: some browsers don't fire voiceschanged if they are already there
      setTimeout(startSpeech, 100);
    } else {
      startSpeech();
    }

    setTimeout(() => resolve(true), 6000);
  });
}

/**
 * Synthesizes and plays text. 
 * Uzbek is explicitly blocked from pronunciation.
 */
export async function speak(text: string, lang: Language, existingData?: string): Promise<string | undefined> {
  if (!text || !text.trim()) return;

  // Explicitly remove Uzbek pronunciation as requested.
  if (lang === 'Uzbek') return;

  const ctx = getAudioContext();
  if (!ctx) return;

  // On every play attempt, try to ensure context is resumed
  if (ctx.state === 'suspended') {
    ctx.resume().catch(e => console.error("Auto-resume failed", e));
  }

  const playBuffer = (buffer: AudioBuffer) => {
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  };

  // 1. Play existing cached audio data if provided
  if (existingData) {
    try {
      const cacheKey = `data:${existingData.substring(0, 32)}`;
      let buffer = audioBufferCache.get(cacheKey);
      if (!buffer) {
        buffer = await decodeAudioData(decode(existingData), ctx, 24000, 1);
        audioBufferCache.set(cacheKey, buffer);
      }
      playBuffer(buffer);
      return existingData;
    } catch (e) {
      console.warn("Cached audio playback failed, falling back.");
    }
  }

  // 2. Use Optimized Native TTS for German, English, Arabic, Russian
  if (NATIVE_LANG_CODES[lang]) {
    const success = await speakNative(text, lang);
    if (success) return undefined; 
  }

  // 3. Fallback to Gemini API for non-Uzbek languages
  const memoryCacheKey = `${text.trim()}:${lang}`;
  if (audioBufferCache.has(memoryCacheKey)) {
    playBuffer(audioBufferCache.get(memoryCacheKey)!);
    return undefined;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const voiceName = VOICE_MAPPING[lang] || 'Puck';

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say clearly: ${text}` }] }],
      config: {
        // Fix: Corrected typo in property name: responseModalities
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
    audioBufferCache.set(memoryCacheKey, audioBuffer);
    playBuffer(audioBuffer);

    return base64Audio;
  } catch (error) {
    console.error("TTS Engine Failure:", error);
    return undefined;
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";
import { normalizeQuery } from "../utils/normalization";

const queryCache = new Map<string, LexicalEntry>();

const generateId = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
  } catch (e) {}
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

/**
 * Robust JSON cleaner for structured LLM responses.
 */
function cleanJsonResponse(text: string): string {
  if (!text || typeof text !== 'string') return "{}";
  let cleaned = text.trim();
  if (cleaned.startsWith("```")) {
    cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/, "").replace(/\n?```$/, "");
  }
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    cleaned = cleaned.substring(firstBrace, lastBrace + 1);
  }
  // Strip control characters that break JSON.parse on mobile devices
  cleaned = cleaned.replace(/[\u0000-\u001F\u007F-\u009F\uFEFF]/g, "");
  return cleaned.trim();
}

/**
 * Fetches the complete lexical, philological, and cultural profile of a word in one pass.
 * Optimized for API frequency and latency.
 */
export async function fetchCompleteLexicalEntry(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const normQuery = normalizeQuery(query, sourceLanguage);
  const cacheKey = `${normQuery}:${sourceLanguage}:${targetLanguage}`;

  if (queryCache.has(cacheKey)) {
    return queryCache.get(cacheKey)!;
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `You are a world-class philologist and lexicographer. 
  Provide a complete scholarly profile of the term. 
  Include: exact translation, lemma, gender, CEFR level, etymology, 2-3 literary quotes, and register-specific usage notes.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Examine the term "${query}" from ${sourceLanguage} to ${targetLanguage}.`,
      config: {
        systemInstruction,
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            term: { type: Type.STRING },
            lemma: { type: Type.STRING },
            mainTranslation: { type: Type.STRING },
            partOfSpeech: { type: Type.STRING },
            gender: { type: Type.STRING },
            plural: { type: Type.STRING },
            cefrLevel: { type: Type.STRING },
            etymology: { type: Type.STRING },
            usage: { type: Type.STRING },
            register: { type: Type.STRING },
            notes: { type: Type.STRING },
            synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
            variations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  confidence: { type: Type.NUMBER }
                }
              }
            },
            literature: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  source: { type: Type.STRING },
                  author: { type: Type.STRING }
                }
              }
            },
            idioms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  context: { type: Type.STRING }
                }
              }
            }
          },
          required: ["term", "mainTranslation", "partOfSpeech", "etymology"]
        }
      }
    });

    const rawData = JSON.parse(cleanJsonResponse(response.text));

    const entry: LexicalEntry = {
      id: generateId(),
      term: rawData.term || query,
      lemma: rawData.lemma,
      normalizedTerm: normQuery,
      mainTranslation: rawData.mainTranslation || "Not found",
      sourceLang: sourceLanguage,
      targetLang: targetLanguage,
      cefrLevel: rawData.cefrLevel,
      philology: {
        etymology: rawData.etymology || "Archive record accessed.",
        partOfSpeech: rawData.partOfSpeech || "n/a",
        gender: rawData.gender,
        plural: rawData.plural
      },
      culture: {
        usage: rawData.usage || "",
        register: (rawData.register?.toLowerCase() as any) || 'neutral',
        notes: rawData.notes || ""
      },
      synonyms: rawData.synonyms || [],
      variations: (rawData.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
      literature: rawData.literature || [],
      realLifeSentences: rawData.idioms || [],
      idioms: rawData.idioms || [],
      timestamp: Date.now()
    };

    queryCache.set(cacheKey, entry);
    return entry;
  } catch (err) {
    console.error("Consolidated Lexical Fetch Error:", err);
    throw err;
  }
}

export async function getDailyInsight() {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Return one surprising linguistic fact as JSON: {title, fact}.",
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            fact: { type: Type.STRING }
          }
        }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (err) {
    return { title: "Lexical Continuity", fact: "Language is history." };
  }
}

function shuffleArray<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const context = entries.map(e => `${e.term} -> ${e.mainTranslation}`).join(", ");
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create 3-choice quiz for: ${context}. JSON Array of objects with question, correctAnswer, options (3 items), explanation.`,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              correctAnswer: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              explanation: { type: Type.STRING }
            },
            required: ["question", "correctAnswer", "options", "explanation"]
          }
        }
      }
    });
    const cleaned = cleanJsonResponse(response.text || "[]");
    return JSON.parse(cleaned).map((q: any) => ({ ...q, options: shuffleArray(q.options || []) }));
  } catch (err) {
    return [];
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { fetchCompleteLexicalEntry } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import { triggerHaptic } from '../services/telegram';
import { normalizeQuery } from '../utils/normalization';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS',
  Arabic: 'ARA'
};

const LANGUAGES_LIST: Language[] = ['German', 'Uzbek', 'English', 'Russian', 'Arabic'];

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  selectedEntry,
  onEntryClick,
  onStartArena
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexSourceLang');
    return (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'German');
  });
  const [targetLang, setTargetLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexTargetLang');
    const initialTarget = (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'Uzbek');
    const initialSource = localStorage.getItem('lexSourceLang') || 'German';
    return (initialTarget === initialSource) ? (initialSource === 'Uzbek' ? 'German' : 'Uzbek') : initialTarget;
  });

  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [voiceSupported, setVoiceSupported] = useState(true);
  const [voiceStatusMsg, setVoiceStatusMsg] = useState<string | null>(null);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [needsKeySelection, setNeedsKeySelection] = useState(false);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const currentSearchIdRef = useRef<string | null>(null);

  const handleSourceChange = (newLang: Language) => {
    if (newLang === targetLang) {
      setTargetLang(sourceLang);
      localStorage.setItem('lexTargetLang', sourceLang);
    }
    setSourceLang(newLang);
    localStorage.setItem('lexSourceLang', newLang);
    triggerHaptic('light');
  };

  const handleTargetChange = (newLang: Language) => {
    if (newLang === sourceLang) {
      setSourceLang(targetLang);
      localStorage.setItem('lexSourceLang', targetLang);
    }
    setTargetLang(newLang);
    localStorage.setItem('lexTargetLang', newLang);
    triggerHaptic('light');
  };

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setVoiceSupported(false);
    }
  }, []);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      setShowSuggestions(false);
      localStorage.setItem('lexSourceLang', selectedEntry.sourceLang);
      localStorage.setItem('lexTargetLang', selectedEntry.targetLang);
      currentSearchIdRef.current = selectedEntry.id;
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    if (loading) {
      setShowSuggestions(false);
      setSuggestions([]);
      return;
    }

    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim();
      if (trimmedQuery.length >= 2) {
        const normSearch = normalizeQuery(trimmedQuery, sourceLang);

        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && normalizeQuery(e.term, e.sourceLang).startsWith(normSearch))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && normalizeQuery(e.term, sourceLang).startsWith(normSearch))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(normSearch, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {}

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        if (!loading && !(result && normalizeQuery(result.term, sourceLang) === normSearch)) {
          setSuggestions(unique);
          setShowSuggestions(unique.length > 0);
          setSelectedIndex(-1);
        }
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history, loading, result]);

  const startVoiceSearch = async () => {
    await resumeAudioContext().catch(() => {});
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setVoiceStatusMsg("Voice access restricted");
      triggerHaptic('error');
      setTimeout(() => setVoiceStatusMsg(null), 3000);
      return;
    }
    const recognition = new SpeechRecognition();
    const langCodes: Record<Language, string> = {
      German: 'de-DE', Uzbek: 'uz-UZ', English: 'en-US', Russian: 'ru-RU', Arabic: 'ar-SA'
    };
    recognition.lang = langCodes[sourceLang];
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;
    recognition.onstart = () => { setIsListening(true); triggerHaptic('light'); };
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setQuery(transcript);
      handleSearch(transcript);
    };
    recognition.onerror = () => { setIsListening(false); triggerHaptic('error'); };
    recognition.onend = () => setIsListening(false);
    try { recognition.start(); } catch (e) { setIsListening(false); }
  };

  const handleOpenKeySelector = async () => {
    if ((window as any).aistudio?.openSelectKey) {
      triggerHaptic('heavy');
      await (window as any).aistudio.openSelectKey();
      setNeedsKeySelection(false);
      handleSearch();
    } else {
      window.open('https://ai.google.dev/gemini-api/docs/billing', '_blank');
    }
  };

  const handleSearch = async (overrideQuery?: string) => {
    await resumeAudioContext().catch(() => {});
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;
    setShowSuggestions(false);
    setSearchError(null);
    setNeedsKeySelection(false);
    if (inputRef.current) inputRef.current.blur();
    const normQuery = normalizeQuery(cleanQuery, sourceLang);
    setQuery(cleanQuery);
    const searchId = Math.random().toString(36).substring(7);
    currentSearchIdRef.current = searchId;

    const localHit = history.find(e => 
      normalizeQuery(e.term, e.sourceLang) === normQuery && 
      e.sourceLang === sourceLang && 
      e.targetLang === targetLang
    );
    if (localHit) {
      setResult(localHit);
      if (autoAudio) {
        const sourceData = await speak(cleanQuery, sourceLang, localHit.sourceAudio);
        if (currentSearchIdRef.current === searchId) {
          const targetData = await speak(localHit.mainTranslation, targetLang, localHit.targetAudio);
          if ((sourceData && !localHit.sourceAudio) || (targetData && !localHit.targetAudio)) {
            const updated = { ...localHit };
            if (sourceData) updated.sourceAudio = sourceData;
            if (targetData) updated.targetAudio = targetData;
            onEntrySaved(updated);
          }
        }
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (currentSearchIdRef.current !== searchId) return;
      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          const sourceData = await speak(cleanQuery, sourceLang, globalHit.sourceAudio);
          if (currentSearchIdRef.current === searchId) {
            const targetData = await speak(globalHit.mainTranslation, targetLang, globalHit.targetAudio);
            if ((sourceData && !globalHit.sourceAudio) || (targetData && !globalHit.targetAudio)) {
              const updated = { ...globalHit };
              if (sourceData) updated.sourceAudio = sourceData;
              if (targetData) updated.targetAudio = targetData;
              onEntrySaved(updated);
              saveGlobalEntry(updated);
            }
          }
        }
        return;
      }

      // Optimized single-pass fetch
      const fullEntry = await fetchCompleteLexicalEntry(cleanQuery, sourceLang, targetLang);
      if (currentSearchIdRef.current !== searchId) return;

      setResult(fullEntry);
      setLoading(false);

      if (autoAudio) {
        const sourceData = await speak(cleanQuery, sourceLang);
        if (currentSearchIdRef.current === searchId) {
          const targetData = await speak(fullEntry.mainTranslation, targetLang);
          if (sourceData) fullEntry.sourceAudio = sourceData;
          if (targetData) fullEntry.targetAudio = targetData;
          onEntrySaved(fullEntry);
          saveGlobalEntry(fullEntry);
        }
      } else {
        onEntrySaved(fullEntry);
        saveGlobalEntry(fullEntry);
      }
    } catch (err: any) {
      if (currentSearchIdRef.current !== searchId) return;
      if (err.message?.includes("ENTITY_NOT_FOUND") || err.message?.includes("NOT_FOUND")) {
        setSearchError("Linguistic node unavailable in this project region.");
        setNeedsKeySelection(true);
      } else if (err.message?.includes("PERMISSION_DENIED")) {
        setSearchError("Archival access denied. Verify project key.");
        setNeedsKeySelection(true);
      } else {
        setSearchError("The archive is silent. Network or API error.");
      }
      setLoading(false);
    }
  };

