import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";
import { normalizeQuery } from "../utils/normalization";

const queryCache = new Map<string, LexicalEntry>();

const generateId = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
  } catch (e) {}
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

/**
 * Robust JSON cleaner for structured LLM responses.
 */
function cleanJsonResponse(text: string): string {
  if (!text || typeof text !== 'string') return "{}";
  let cleaned = text.trim();
  if (cleaned.startsWith("```")) {
    cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/, "").replace(/\n?```$/, "");
  }
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    cleaned = cleaned.substring(firstBrace, lastBrace + 1);
  }
  cleaned = cleaned.replace(/[\u0000-\u001F\u007F-\u009F\uFEFF]/g, "");
  return cleaned.trim();
}

/**
 * Fetches the complete lexical, philological, and cultural profile.
 */
export async function fetchCompleteLexicalEntry(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const normQuery = normalizeQuery(query, sourceLanguage);
  const cacheKey = `${normQuery}:${sourceLanguage}:${targetLanguage}`;

  if (queryCache.has(cacheKey)) {
    return queryCache.get(cacheKey)!;
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `You are a world-class philologist and cultural historian. 
  Provide a complete scholarly profile of the term. 
  Crucial: Include a rich "cultural" section explaining the register, social usage, and any cultural nuances in the target language.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Examine the term "${query}" from ${sourceLanguage} to ${targetLanguage}.`,
      config: {
        systemInstruction,
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            term: { type: Type.STRING },
            lemma: { type: Type.STRING },
            mainTranslation: { type: Type.STRING },
            partOfSpeech: { type: Type.STRING },
            gender: { type: Type.STRING },
            plural: { type: Type.STRING },
            cefrLevel: { type: Type.STRING },
            etymology: { type: Type.STRING },
            culture: {
              type: Type.OBJECT,
              properties: {
                usage: { type: Type.STRING, description: "How the word is used socially." },
                register: { type: Type.STRING, description: "formal, informal, or neutral" },
                notes: { type: Type.STRING, description: "Historical or cultural context." }
              },
              required: ["usage", "register", "notes"]
            },
            synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
            variations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  confidence: { type: Type.NUMBER }
                }
              }
            },
            literature: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  source: { type: Type.STRING },
                  author: { type: Type.STRING }
                }
              }
            },
            idioms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  context: { type: Type.STRING }
                }
              }
            }
          },
          required: ["term", "mainTranslation", "partOfSpeech", "etymology", "culture"]
        }
      }
    });

    const rawData = JSON.parse(cleanJsonResponse(response.text));

    const entry: LexicalEntry = {
      id: generateId(),
      term: rawData.term || query,
      lemma: rawData.lemma,
      normalizedTerm: normQuery,
      mainTranslation: rawData.mainTranslation || "Not found",
      sourceLang: sourceLanguage,
      targetLang: targetLanguage,
      cefrLevel: rawData.cefrLevel,
      philology: {
        etymology: rawData.etymology || "Archive record accessed.",
        partOfSpeech: rawData.partOfSpeech || "n/a",
        gender: rawData.gender,
        plural: rawData.plural
      },
      culture: {
        usage: rawData.culture?.usage || "",
        register: (rawData.culture?.register?.toLowerCase() as any) || 'neutral',
        notes: rawData.culture?.notes || ""
      },
      synonyms: rawData.synonyms || [],
      variations: (rawData.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
      literature: rawData.literature || [],
      realLifeSentences: rawData.idioms || [],
      idioms: rawData.idioms || [],
      timestamp: Date.now()
    };

    queryCache.set(cacheKey, entry);
    return entry;
  } catch (err) {
    console.error("Consolidated Lexical Fetch Error:", err);
    throw err;
  }
}

export async function getDailyInsight() {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
