export default ResultCard;

import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const audioBufferCache = new Map<string, AudioBuffer>();
let sharedAudioCtx: AudioContext | null = null;
let isResuming = false;
let isUnlocked = false;

// BCP 47 Language Mapping for Native Synthesis
const NATIVE_LANG_CODES: Record<string, string> = {
  'German': 'de-DE',
  'English': 'en-US',
  'Arabic': 'ar-SA',
  'Russian': 'ru-RU'
};

/**
 * Standardizes the AudioContext retrieval.
 */
export function getAudioContext() {
  if (!sharedAudioCtx) {
    const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
    if (AudioContextClass) {
      // 44100 is most reliable across all Android/iOS hardware
      sharedAudioCtx = new AudioContextClass();
    }
  }
  return sharedAudioCtx;
}

/**
 * Robustly resumes the AudioContext within a user gesture.
 */
export async function resumeAudioContext(): Promise<void> {
  const ctx = getAudioContext();
  if (!ctx || isResuming) return;

  if (ctx.state === 'running' && isUnlocked) return;

  isResuming = true;
  try {
    await ctx.resume();
    // Prime the hardware with silence
    const buffer = ctx.createBuffer(1, 1, 22050);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
    isUnlocked = true;
  } catch (e) {
    console.warn("Audio unlock failed:", e);
  } finally {
    isResuming = false;
  }
}

/**
 * Decodes base64 pcm data safely.
 */
function decode(base64: string): Uint8Array {
  const normalized = base64.replace(/[^A-Za-z0-9+/=]/g, "");
  try {
    const binaryString = atob(normalized);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  } catch (e) {
    console.error("Base64 decoding failed", e);
    return new Uint8Array(0);
  }
}

/**
 * Decodes raw PCM bytes to AudioBuffer using DataView for bit-accuracy.
 * Fixes "throat-ached" distortion by ensuring clean 16-bit to float conversion.
 */
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const buffer = data.buffer;
  const view = new DataView(buffer);
  const frameCount = data.byteLength / (2 * numChannels);
  const audioBuffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = audioBuffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      // Using Little Endian as per Gemini API standard for raw PCM
      const offset = (i * numChannels + channel) * 2;
      const int16 = view.getInt16(offset, true);
      channelData[i] = int16 / 32768.0;
    }
  }
  return audioBuffer;
}

/**
 * Returns a high-quality voice if available.
 */
function getHighQualityVoice(code: string): SpeechSynthesisVoice | null {
  const voices = window.speechSynthesis.getVoices();
  const langVoices = voices.filter(v => v.lang.replace('_', '-').startsWith(code));
  if (langVoices.length === 0) return null;
  return langVoices.find(v => v.name.includes("Google") && !v.name.includes("Compact")) || langVoices[0];
}

/**
 * Uses browser's built-in SpeechSynthesis.
 */
async function speakNative(text: string, lang: Language): Promise<boolean> {
  const code = NATIVE_LANG_CODES[lang];
  if (!code || !window.speechSynthesis) return false;

  return new Promise((resolve) => {
    window.speechSynthesis.cancel();
    const startSpeech = () => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = code;
      const voice = getHighQualityVoice(code);
      if (voice) utterance.voice = voice;
      (window as any)._currentUtterance = utterance;
      utterance.onend = () => { resolve(true); };
      utterance.onerror = () => { resolve(false); };
      window.speechSynthesis.speak(utterance);
    };
    if (window.speechSynthesis.getVoices().length === 0) {
      setTimeout(startSpeech, 100);
    } else {
      startSpeech();
    }
  });
}

/**
 * Synthesizes and plays text. 
 * Uzbek is explicitly blocked.
 */
export async function speak(text: string, lang: Language, existingData?: string): Promise<string | undefined> {
  if (!text || !text.trim() || lang === 'Uzbek') return;

  const ctx = getAudioContext();
  if (!ctx) return;

  if (ctx.state === 'suspended') {
    ctx.resume().catch(() => {});
  }

  const playBuffer = (buffer: AudioBuffer) => {
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  };

  // 1. Play existing cached audio
  if (existingData) {
    try {
      const cacheKey = `data:${existingData.substring(0, 32)}`;
      let buffer = audioBufferCache.get(cacheKey);
      if (!buffer) {
        buffer = await decodeAudioData(decode(existingData), ctx, 24000, 1);
        audioBufferCache.set(cacheKey, buffer);
      }
      playBuffer(buffer);
      return existingData;
    } catch (e) {}
  }

  // 2. Use Native TTS for optimized mobile performance
  if (NATIVE_LANG_CODES[lang]) {
    const success = await speakNative(text, lang);
    if (success) return undefined; 
  }

  // 3. High-Fidelity Gemini TTS fallback
  const memoryCacheKey = `${text.trim()}:${lang}`;
  if (audioBufferCache.has(memoryCacheKey)) {
    playBuffer(audioBufferCache.get(memoryCacheKey)!);
    return undefined;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    // Use 'Puck' or 'Kore' for clearer, more philological tones
    const voiceName = (lang === 'Arabic' || lang === 'German') ? 'Kore' : 'Puck';

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
    audioBufferCache.set(memoryCacheKey, audioBuffer);
    playBuffer(audioBuffer);

    return base64Audio;
  } catch (error) {
    console.error("High-Fidelity TTS Error:", error);
    return undefined;
  }
}

