      }
    });

    const rawData = JSON.parse(cleanJsonResponse(response.text));

    const entry: LexicalEntry = {
      id: generateId(),
      term: rawData.term || query,
      normalizedTerm: normQuery,
      mainTranslation: rawData.mainTranslation,
      sourceLang: sourceLanguage,
      targetLang: targetLanguage,
      cefrLevel: rawData.cefrLevel || "N/A",
      philology: {
        partOfSpeech: rawData.philology.partOfSpeech,
        etymology: rawData.philology.etymology,
        gender: rawData.philology.gender || "not applicable",
        plural: rawData.philology.plural || "n/a"
      },
      culture: {
        notes: rawData.culture.notes,
        usage: rawData.culture.usage,
        register: rawData.culture.register || "neutral"
      },
      synonyms: rawData.synonyms || [],
      variations: (rawData.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
      literature: rawData.literature || [],
      idioms: rawData.idioms || [],
      realLifeSentences: rawData.idioms || [], // Synced per user example
      timestamp: Date.now()
    };

    queryCache.set(cacheKey, entry);
    return entry;
  } catch (err) {
    console.error("Lexical Retrieval Failure:", err);
    throw err;
  }
}

