  const context = entries.map(e => `${e.term} -> ${e.mainTranslation}`).join(", ");
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create 3-choice quiz for: ${context}. JSON Array of objects with question, correctAnswer, options (3 items), explanation.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              correctAnswer: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              explanation: { type: Type.STRING }
            }
          }
        }
      }
    });
    const cleaned = cleanJsonResponse(response.text || "[]");
    return JSON.parse(cleaned).map((q: any) => ({ ...q, options: shuffleArray(q.options || []) }));
  } catch (err) {
    return [];
  }
}

import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const audioBufferCache = new Map<string, AudioBuffer>();
let sharedAudioCtx: AudioContext | null = null;
let isUnlocked = false;

// BCP 47 Language Mapping for Native Synthesis
const NATIVE_LANG_CODES: Record<string, string> = {
  'German': 'de-DE',
  'English': 'en-US',
  'Arabic': 'ar-SA',
  'Russian': 'ru-RU'
};

export function getAudioContext() {
  if (!sharedAudioCtx) {
    const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
    if (AudioContextClass) {
      // Create context with hardware defaults, but decoding will be locked to source rate
      sharedAudioCtx = new AudioContextClass();
    }
  }
  return sharedAudioCtx;
}

/**
 * Primes the audio hardware for Telegram's mobile webview.
 */
export async function resumeAudioContext(): Promise<void> {
  const ctx = getAudioContext();
  if (!ctx || isUnlocked) return;

  try {
    if (ctx.state === 'suspended') await ctx.resume();

    // Play a frame of silence to unlock iOS/Android hardware
    const buffer = ctx.createBuffer(1, 1, 22050);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
    isUnlocked = true;
  } catch (e) {
    console.warn("Audio Context unlock attempt failed:", e);
  }
}

function decodeBase64(base64: string): Uint8Array {
  const normalized = base64.replace(/[^A-Za-z0-9+/=]/g, "");
  try {
    const binaryString = atob(normalized);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  } catch (e) {
    console.error("Base64 decoding failed", e);
    return new Uint8Array(0);
  }
}

/**
 * High-Precision PCM Decoding with Clamping to prevent 'throat-ache' distortion.
 */
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const buffer = data.buffer;
  const view = new DataView(buffer);
  const frameCount = data.byteLength / (2 * numChannels);

  // We lock the audio buffer to the source sample rate (24000 for Gemini)
  const audioBuffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = audioBuffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      const offset = (i * numChannels + channel) * 2;
      // Byte alignment check
      if (offset + 1 >= view.byteLength) break;

      const int16 = view.getInt16(offset, true);
      // Normalized Float conversion with Clamping for signal integrity
      let floatVal = int16 / 32768.0;
      if (floatVal > 1.0) floatVal = 1.0;
      if (floatVal < -1.0) floatVal = -1.0;
      channelData[i] = floatVal;
    }
  }
  return audioBuffer;
}

async function speakNative(text: string, lang: Language): Promise<boolean> {
  const code = NATIVE_LANG_CODES[lang];
  if (!code || !window.speechSynthesis) return false;

  return new Promise((resolve) => {
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = code;

    // Attempt to pick a higher quality system voice
    const voices = window.speechSynthesis.getVoices();
    const voice = voices.find(v => v.lang.startsWith(code.split('-')[0]) && !v.name.includes("Compact")) || voices[0];
    if (voice) utterance.voice = voice;

    (window as any)._lastUtterance = utterance; // Prevent GC
    utterance.onend = () => resolve(true);
    utterance.onerror = () => resolve(false);
    window.speechSynthesis.speak(utterance);

    // Fallback if it hangs
    setTimeout(() => resolve(true), 5000);
  });
}

/**
 * Main Speak interface. 
 * Correctly blocks Uzbek pronunciation and uses high-fidelity models for others.
 */
export async function speak(text: string, lang: Language, existingData?: string): Promise<string | undefined> {
  if (!text || !text.trim() || lang === 'Uzbek') return;

  const ctx = getAudioContext();
  if (!ctx) return;

  if (ctx.state === 'suspended') {
    ctx.resume().catch(() => {});
  }

  const playBuffer = (buffer: AudioBuffer) => {
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  };

  if (existingData) {
    try {
      const buffer = await decodeAudioData(decodeBase64(existingData), ctx, 24000, 1);
      playBuffer(buffer);
      return existingData;
    } catch (e) {
      console.warn("Cached audio playback failed");
    }
  }

  // Use Native TTS for standard languages for zero latency
  if (NATIVE_LANG_CODES[lang]) {
    const success = await speakNative(text, lang);
    if (success) return undefined;
  }

  // Gemini TTS with High-Fidelity Voices
  const memoryCacheKey = `${text.trim()}:${lang}`;
  if (audioBufferCache.has(memoryCacheKey)) {
    playBuffer(audioBufferCache.get(memoryCacheKey)!);
    return undefined;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    // Puck and Kore are much smoother and more professional
    const voiceName = (lang === 'Arabic' || lang === 'German') ? 'Kore' : 'Puck';

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), ctx, 24000, 1);
    audioBufferCache.set(memoryCacheKey, audioBuffer);
    playBuffer(audioBuffer);

    return base64Audio;
  } catch (error) {
    console.error("Audio Engine Exception:", error);
    return undefined;
  }
}

