const generateId = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
  } catch (e) {}
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

function cleanJsonResponse(text: string): string {
  if (!text) return "{}";
  let cleaned = text.trim();

  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    cleaned = cleaned.substring(firstBrace, lastBrace + 1);
  }
  // Strip control characters that often break JSON parsing in mobile webviews
  cleaned = cleaned.replace(/[\u0000-\u001F\u007F-\u009F\uFEFF]/g, "");
  return cleaned.trim();
}

/**
 * Single-pass high-performance fetch for complete lexical data.
 */
export async function fetchCompleteLexicalEntry(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `You are an elite philologist. Provide a comprehensive lexical record for the given term.
  The "culture" object MUST contain "notes", "usage", and "register". 
  The "idioms" should contain high-quality usage examples.
  Register should be "Standard", "Formal", "Informal", or "Poetic".`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze the word "${query}" from ${sourceLanguage} to ${targetLanguage}.`,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          lemma: { type: Type.STRING },
          mainTranslation: { type: Type.STRING },
          cefrLevel: { type: Type.STRING },
          philology: {
            type: Type.OBJECT,
            properties: {
              partOfSpeech: { type: Type.STRING },
              etymology: { type: Type.STRING },
              gender: { type: Type.STRING },
              plural: { type: Type.STRING }
            },
            required: ["partOfSpeech", "etymology"]
          },
          culture: {
            type: Type.OBJECT,
            properties: {
              notes: { type: Type.STRING },
              usage: { type: Type.STRING },
              register: { type: Type.STRING }
            },
            required: ["notes", "usage", "register"]
          },
          synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
          variations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                confidence: { type: Type.NUMBER }
              }
            }
          },
          literature: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                source: { type: Type.STRING },
                author: { type: Type.STRING }
              }
            }
          },
          idioms: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                context: { type: Type.STRING }
              }
            }
          }
        },
        required: ["term", "mainTranslation", "philology", "culture", "idioms"]
      }
    }
  });

  const rawData = JSON.parse(cleanJsonResponse(response.text));

  return {
    id: generateId(),
    term: rawData.term || query,
    lemma: rawData.lemma,
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: rawData.mainTranslation,
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    cefrLevel: rawData.cefrLevel || "N/A",
    philology: {
      partOfSpeech: rawData.philology.partOfSpeech,
      etymology: rawData.philology.etymology,
      gender: rawData.philology.gender || "not applicable",
      plural: rawData.philology.plural || "n/a"
    },
    culture: {
      notes: rawData.culture.notes,
      usage: rawData.culture.usage,
      register: rawData.culture.register || "Standard"
    },
    synonyms: rawData.synonyms || [],
    variations: (rawData.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
    literature: rawData.literature || [],
    idioms: rawData.idioms || [],
    realLifeSentences: rawData.idioms || [],
    timestamp: Date.now()
  };
}

