function shuffleArray<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const context = entries.map(e => `${e.term} -> ${e.mainTranslation}`).join(", ");
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create 3-choice quiz for: ${context}. JSON Array.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              correctAnswer: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              explanation: { type: Type.STRING }
            }
          }
        }
      }
    });
    const questions = JSON.parse(cleanJsonResponse(response.text || "[]"));
    return questions.map((q: any) => ({ ...q, options: shuffleArray(q.options) }));
  } catch (err) {
    return [];
  }
}

import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";

const audioBufferCache = new Map<string, AudioBuffer>();
let sharedAudioCtx: AudioContext | null = null;
let isUnlocked = false;

export function getAudioContext() {
  if (!sharedAudioCtx) {
    const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
    if (AudioContextClass) {
      sharedAudioCtx = new AudioContextClass();
    }
  }
  return sharedAudioCtx;
}

/**
 * Primes the audio hardware for mobile webviews (Telegram Android/iOS).
 */
export async function resumeAudioContext(): Promise<void> {
  const ctx = getAudioContext();
  if (!ctx || isUnlocked) return;

  try {
    if (ctx.state === 'suspended') await ctx.resume();
    // Warm up the hardware with a frame of silence
    const buffer = ctx.createBuffer(1, 1, 22050);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
    isUnlocked = true;
  } catch (e) {
    console.warn("Audio Context unlock failed", e);
  }
}

function decodeBase64(base64: string): Uint8Array {
  const normalized = base64.replace(/[^A-Za-z0-9+/=]/g, "");
  try {
    const binaryString = atob(normalized);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  } catch (e) {
    return new Uint8Array(0);
  }
}

/**
 * Bit-accurate PCM decoding with signal clamping to fix 'throat-ache' distortion.
 */
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const buffer = data.buffer;
  const view = new DataView(buffer);
  const frameCount = data.byteLength / (2 * numChannels);
  const audioBuffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = audioBuffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      const offset = (i * numChannels + channel) * 2;
      if (offset + 1 >= view.byteLength) break;

      const int16 = view.getInt16(offset, true); // Gemini uses Little Endian
      // Normalize and clamp to prevent clipping distortion
      let floatVal = int16 / 32768.0;
      if (floatVal > 1.0) floatVal = 1.0;
      if (floatVal < -1.0) floatVal = -1.0;
      channelData[i] = floatVal;
    }
  }
  return audioBuffer;
}

/**
 * High-fidelity synthesis engine. Uzbek remains muted per request.
 */
export async function speak(text: string, lang: Language, existingAudio?: string): Promise<string | undefined> {
  if (!text || !text.trim() || lang === 'Uzbek') return;

  const ctx = getAudioContext();
  if (!ctx) return;

  if (ctx.state === 'suspended') {
    ctx.resume().catch(() => {});
  }

  const playBuffer = (buffer: AudioBuffer) => {
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  };

  const cacheKey = `${text.trim()}:${lang}`;

  // Use existing base64 audio if provided
  if (existingAudio) {
    try {
      const buffer = await decodeAudioData(decodeBase64(existingAudio), ctx, 24000, 1);
      playBuffer(buffer);
      return existingAudio;
    } catch (e) {}
  }

  if (audioBufferCache.has(cacheKey)) {
    playBuffer(audioBufferCache.get(cacheKey)!);
    return undefined;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    // Use 'Kore' and 'Puck' for professional, resonant tones
    const voiceName = (lang === 'Arabic' || lang === 'German') ? 'Kore' : 'Puck';

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), ctx, 24000, 1);
    audioBufferCache.set(cacheKey, audioBuffer);
    playBuffer(audioBuffer);

    return base64Audio;
  } catch (error) {
    console.error("TTS Engine Failure:", error);
    return undefined;
  }
}

