import React, { useState, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { fetchCompleteLexicalEntry } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import { triggerHaptic } from '../services/telegram';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS',
  Arabic: 'ARA'
};

const LANGUAGES_LIST: Language[] = ['German', 'Uzbek', 'English', 'Russian', 'Arabic'];

const normalizeQuery = (text: string, lang: Language): string => {
  if (!text) return "";
  let res = text.trim().toLowerCase();
  res = res.replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'") 
           .replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"')
           .replace(/\u00A0/g, " ");
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`‘]/g, "'");
  }
  return res.trim();
};

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  selectedEntry,
  onEntryClick,
  onStartArena
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexSourceLang');
    return (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'German');
  });
  const [targetLang, setTargetLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexTargetLang');
    return (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'Uzbek');
  });

  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [voiceSupported, setVoiceSupported] = useState(true);
  const [voiceStatusMsg, setVoiceStatusMsg] = useState<string | null>(null);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [searchError, setSearchError] = useState<string | null>(null);

  const inputRef = useRef<HTMLInputElement>(null);
  const currentSearchIdRef = useRef<string | null>(null);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) setVoiceSupported(false);
  }, []);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      setShowSuggestions(false);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    if (loading) {
      setShowSuggestions(false);
      setSuggestions([]);
      return;
    }

    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const normSearch = normalizeQuery(trimmedQuery, sourceLang);
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && normalizeQuery(e.term, e.sourceLang).startsWith(normSearch))
          .map(e => ({ term: e.term, source: 'local' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {}

        const combined = [...localMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        if (!loading && !(result && result.term.toLowerCase() === query.trim().toLowerCase())) {
          setSuggestions(unique);
          setShowSuggestions(unique.length > 0);
          setSelectedIndex(-1);
        }
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 200);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history, loading, result]);

  const handleSearch = async (overrideQuery?: string) => {
    await resumeAudioContext().catch(() => {});
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setShowSuggestions(false);
    setSearchError(null);
    if (inputRef.current) inputRef.current.blur();
    setQuery(cleanQuery);

    const searchId = Math.random().toString(36);
    currentSearchIdRef.current = searchId;
    const normQuery = normalizeQuery(cleanQuery, sourceLang);

    const localHit = history.find(e => 
      normalizeQuery(e.term, e.sourceLang) === normQuery && 
      e.sourceLang === sourceLang && 
      e.targetLang === targetLang
    );

    if (localHit) {
      setResult(localHit);
      if (autoAudio) {
        const sAudio = await speak(cleanQuery, sourceLang, localHit.sourceAudio);
        if (currentSearchIdRef.current === searchId) {
          const tAudio = await speak(localHit.mainTranslation, targetLang, localHit.targetAudio);
          if (sAudio || tAudio) {
            onEntrySaved({ ...localHit, sourceAudio: sAudio || localHit.sourceAudio, targetAudio: tAudio || localHit.targetAudio });
          }
        }
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (currentSearchIdRef.current !== searchId) return;

      if (globalHit) {
        setResult(globalHit);
        setLoading(false);
        onEntrySaved(globalHit);
        if (autoAudio) {
          const sAudio = await speak(cleanQuery, sourceLang, globalHit.sourceAudio);
          if (currentSearchIdRef.current === searchId) {
            const tAudio = await speak(globalHit.mainTranslation, targetLang, globalHit.targetAudio);
            if (sAudio || tAudio) {
              const updated = { ...globalHit, sourceAudio: sAudio || globalHit.sourceAudio, targetAudio: tAudio || globalHit.targetAudio };
              onEntrySaved(updated);
              saveGlobalEntry(updated);
            }
          }
        }
        return;
      }

      const fullEntry = await fetchCompleteLexicalEntry(cleanQuery, sourceLang, targetLang);
      if (currentSearchIdRef.current !== searchId) return;

      setResult(fullEntry);
      setLoading(false);

      if (autoAudio) {
        const sAudio = await speak(cleanQuery, sourceLang);
        if (currentSearchIdRef.current === searchId) {
          const tAudio = await speak(fullEntry.mainTranslation, targetLang);
          const finalEntry = { ...fullEntry, sourceAudio: sAudio, targetAudio: tAudio };
          onEntrySaved(finalEntry);
          saveGlobalEntry(finalEntry);
        }
      } else {
        onEntrySaved(fullEntry);
        saveGlobalEntry(fullEntry);
      }

    } catch (err: any) {
      if (currentSearchIdRef.current !== searchId) return;
      setSearchError("The archive is silent. Network or API error occurred.");
      setLoading(false);
    }
  };

  const startVoiceSearch = async () => {
    await resumeAudioContext().catch(() => {});
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;

    const recognition = new SpeechRecognition();
    const langCodes: Record<Language, string> = { German: 'de-DE', Uzbek: 'uz-UZ', English: 'en-US', Russian: 'ru-RU', Arabic: 'ar-SA' };
    recognition.lang = langCodes[sourceLang];
    recognition.onstart = () => { setIsListening(true); triggerHaptic('light'); };
    recognition.onresult = (e: any) => {
      const transcript = e.results[0][0].transcript;
      setQuery(transcript);
      handleSearch(transcript);
    };
    recognition.onerror = () => setIsListening(false);
    recognition.onend = () => setIsListening(false);
    try { recognition.start(); } catch (e) { setIsListening(false); }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      if (showSuggestions && selectedIndex >= 0) {
        const term = suggestions[selectedIndex].term;
        setQuery(term);
        handleSearch(term);
      } else handleSearch();
    } else if (showSuggestions) {
      if (e.key === 'ArrowDown') { e.preventDefault(); setSelectedIndex(p => (p + 1) % suggestions.length); }
      else if (e.key === 'ArrowUp') { e.preventDefault(); setSelectedIndex(p => (p - 1 + suggestions.length) % suggestions.length); }
    }
  };

  return (
    <div className="space-y-8 md:space-y-16 max-w-7xl mx-auto contain-layout">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-[3px] border-[#7c1a1a] pl-4">
            <span className="text-[9px] uppercase tracking-[0.4em] text-stone-500 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl md:text-3xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[8px] uppercase tracking-[0.2em] text-stone-400 font-bold">Total XP</span>
            </div>
          </div>
        </div>
        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-4 bg-stone-100/50 p-2 rounded-sm w-full sm:w-auto border border-stone-200">
             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} onClick={() => { setSourceLang(full); triggerHaptic('light'); }} className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-400 hover:text-stone-700'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} onClick={() => { setTargetLang(full); triggerHaptic('light'); }} className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-400 hover:text-stone-700'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <button onClick={() => { setAutoAudio(!autoAudio); triggerHaptic('light'); }} className={`flex items-center gap-4 px-5 py-2.5 rounded-full border transition-all ${autoAudio ? 'bg-[#7c1a1a]/5 border-[#7c1a1a]/40' : 'bg-stone-50 border-stone-200'}`}>
            <span className={`text-[11px] uppercase tracking-[0.2em] font-black ${autoAudio ? 'text-[#7c1a1a]' : 'text-stone-500'}`}>AUTO-AUDIO</span>
            <div className={`w-3.5 h-3.5 rounded-full ${autoAudio ? 'bg-[#7c1a1a] shadow-[0_0_10px_rgba(124,26,26,0.4)]' : 'bg-stone-300'}`} />
          </button>
        </div>
      </div>

      <div className="relative w-full">
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }}>
          <div className={`bg-white border-2 transition-all rounded-sm overflow-hidden flex items-stretch min-h-[70px] md:min-h-[110px] ${isListening ? 'border-[#7c1a1a] ring-8 ring-[#7c1a1a]/5' : 'border-stone-200 shadow-md focus-within:border-stone-400 focus-within:shadow-lg'}`}>
            <input ref={inputRef} type="text" value={query} onChange={(e) => setQuery(e.target.value)} onFocus={() => suggestions.length > 0 && setShowSuggestions(true)} onKeyDown={handleKeyDown} spellCheck={false} placeholder={isListening ? "Listening..." : "Summon an inscription..."} className="flex-1 min-w-0 px-6 md:px-10 text-2xl md:text-6xl serif bg-transparent outline-none text-stone-900 lowercase" />
            <div className="flex flex-shrink-0 items-stretch border-l-2 border-stone-50">
              <button type="button" onClick={startVoiceSearch} className="px-4 md:px-8 transition-all flex items-center justify-center border-r border-stone-50 text-stone-400 hover:text-[#7c1a1a]">
                <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 md:w-9 md:h-9" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/></svg>
              </button>
              <button type="submit" disabled={loading} className="px-5 md:px-10 transition-all flex items-center justify-center bg-white hover:bg-[#7c1a1a]/5 text-[#7c1a1a]">
                {loading ? <div className="w-8 h-8 border-4 border-[#7c1a1a] border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8 md:w-12 md:h-12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><line x1="5" y1="12" x2="19" y2="12"></line><polyline points="12 5 19 12 12 19"></polyline></svg>}
              </button>
            </div>
          </div>
        </form>
        {showSuggestions && !loading && (
          <div className="absolute top-full left-0 right-0 bg-white border-2 border-stone-200 shadow-2xl z-20 rounded-b-sm overflow-hidden">
             {suggestions.map((s, idx) => (
               <button key={idx} onClick={() => { setQuery(s.term); handleSearch(s.term); }} className={`w-full text-left px-10 py-6 border-b border-stone-100 last:border-0 flex items-center justify-between ${selectedIndex === idx ? 'bg-stone-50' : 'hover:bg-stone-50/50'}`}>
                 <span className="serif text-2xl md:text-3xl text-stone-700">{s.term}</span>
                 <span className="text-[9px] uppercase tracking-widest font-black text-stone-300">{s.source}</span>
               </button>
             ))}
          </div>
        )}
      </div>

      <div className="min-h-[60px]">
        {loading && (
          <div className="bg-white border border-stone-100 p-16 flex flex-col items-center justify-center space-y-8">
            <div className="w-20 h-20 border-[5px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin"></div>
            <p className="serif text-3xl italic text-stone-300">Consulting the Lexicon...</p>
          </div>
        )}
        {searchError && (
          <div className="bg-[#7c1a1a] text-stone-100 p-12 md:p-20 rounded-sm shadow-xl animate-in zoom-in-95 duration-500 flex flex-col md:flex-row items-center gap-8">
             <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
             <div className="flex-1 text-center md:text-left">
               <h3 className="text-3xl md:text-5xl serif font-black mb-4 lowercase">The Archive is Silent.</h3>
               <p className="text-stone-300 serif italic text-xl md:text-2xl opacity-80">{searchError}</p>
             </div>
          </div>
        )}
        {result && <ResultCard entry={result} onSearchTerm={(term) => handleSearch(term)} onUpdateEntry={onEntrySaved} />}
      </div>

      <div className="pt-16 md:pt-32 border-t border-stone-100">
        <h2 className="text-[14px] uppercase tracking-[0.6em] text-stone-900 font-black mb-12 border-l-[4px] border-[#7c1a1a] pl-8">Archival Chronicles</h2>
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

