          </div>
          <span className="text-[10px] uppercase tracking-[0.4em] text-stone-400 font-black block mb-4">Archival Chronicles</span>
          <h2 className="text-7xl serif font-bold text-stone-900 leading-none">{stats?.totalHistory}</h2>
          <p className="text-[9px] uppercase tracking-widest text-stone-300 mt-4 font-bold italic">Total user interaction history</p>
        </div>
      </div>

      {/* Bulk Inscription Portal */}
      <section className="mb-16 bg-white border border-stone-200 p-8 md:p-12 rounded-sm shadow-sm animate-in slide-in-from-bottom-4">
        <div className="flex items-center gap-6 mb-10">
          <div className="w-12 h-12 bg-[#7c1a1a] rounded-sm flex items-center justify-center text-white">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 2v20"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>
          </div>
          <div>
            <h2 className="text-3xl serif font-black text-stone-900 lowercase">Bulk Inscription Portal</h2>
            <p className="text-[10px] uppercase tracking-[0.4em] text-stone-400 font-black mt-1">Automated Philological Generation</p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
          <div className="lg:col-span-7 space-y-8">
            <div className="space-y-4">
              <label className="text-[11px] uppercase tracking-[0.3em] font-black text-stone-500">Term Manifest (Comma or Newline separated)</label>
