              />
            </div>

            <div className="flex flex-col sm:flex-row gap-6">
              <div className="flex-1 space-y-4">
                <label className="text-[11px] uppercase tracking-[0.3em] font-black text-stone-500">Source Language</label>
                <select 
                  value={sourceLang}
